CREATE TABLE IF NOT EXISTS "site_allowed_models" ("id" INTEGER GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY, "site_id" INTEGER NOT NULL, "model_name" TEXT NOT NULL, "created_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), FOREIGN KEY ("site_id") REFERENCES "sites"("id") ON DELETE CASCADE);
ALTER TABLE "sites" ADD COLUMN "model_filter_mode" TEXT DEFAULT 'deny-list';
CREATE UNIQUE INDEX "site_allowed_models_site_model_unique" ON "site_allowed_models" ("site_id", "model_name");
CREATE INDEX "site_allowed_models_site_id_idx" ON "site_allowed_models" ("site_id");
